module top_module(
    Y ,
    obf_A1,
    A2,
    B1,
    B2
);output Y ;
    input  obf_A1;
    input  A2;
    input  B1;
    input  B2;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    // assign Y to the AND of obf_A1, A2, B1, and B2
    assign Y = obf_A1 & A2 & B1 & B2;

endmodule
